 1	import * as React from 'react';
 2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 3	import { referenceForModel } from '@odf/shared/utils';
 4	import { K8sKind, ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
 5	import {
 6	  Button,
 7	  Popover,
 8	  PopoverProps,
 9	  List,
10	  ListItem,
11	} from '@patternfly/react-core';
12	
13	export const PopoverHelper: React.FC<PopoverHelperProps> = ({
14	  names,
15	  text,
16	  kind,
17	  popoverHasAutoWidth,
18	  testId,
19	}) => {
20	  const { t } = useCustomTranslation();
21	
22	  const popOverBody = (
23	    <List isPlain>
24	      {names?.map((scName) => (
25	        <ListItem key={scName}>
26	          <ResourceLink kind={referenceForModel(kind)} name={scName} />
27	        </ListItem>
28	      ))}
29	    </List>
30	  );
31	
32	  return (
33	    <>
34	      {names?.length ? (
35	        names?.length > 1 ? (
36	          <Popover
37	            aria-label={t('Help')}
38	            bodyContent={popOverBody}
39	            hasAutoWidth={popoverHasAutoWidth}
40	          >
41	            <Button
42	              aria-label={t('Help')}
43	              variant="link"
44	              isInline
45	              data-test-id={testId || null}
46	            >
47	              {`${names?.length} ${text}`}
48	            </Button>
49	          </Popover>
50	        ) : (
51	          <ResourceLink kind={referenceForModel(kind)} name={names?.[0]} />
52	        )
53	      ) : (
54	        '-'
55	      )}
56	    </>
57	  );
58	};
59	
60	type PopoverHelperProps = {
61	  names: string[];
62	  text: string;
63	  kind: K8sKind;
64	  popoverHasAutoWidth?: PopoverProps['hasAutoWidth'];
65	  testId?: string;
66	};

